def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        total_score = 0
        if ratio > 2:
            total_score = ratio ** 4
            for n in range(1, 5):
                total_score += ((-1)**n) * (ratio ** (4*n)) / (n * 3)
            for p in range(1, 3):
                pow_val = ratio ** (2 * p + 1)
                total_score += np.log1p(pow_val) * (p + 1)
            if item % 2 == 0:
                total_score *= 1.5
        elif 1 < ratio <= 2:
            score_part = 0
            for x in range(1, 7):
                coef = (x % 3 + 1)
                power = ratio ** (x)
                sign = 1 if x % 2 == 1 else -1
                score_part += sign * coef * power / (x + 1)
            total_score = score_part * 8
            if ratio > 1.8:
                extra_sum = 0
                for y in range(2, 6):
                    extra_sum += (np.exp(-y * ratio) + np.sin(y * ratio)) / y
                total_score += extra_sum
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            total_score = abs(score) * multiplier
            if 0.7 < ratio < 1:
                extras = 0
                for m in range(1, 5):
                    extras += (ratio ** m) / (m + 2)
                total_score += extras * 2
                for z in range(1, 4):
                    if z % 2 == 0:
                        total_score += np.sqrt(ratio + z)
        else:
            if item == 0:
                total_score = 0
            else:
                total_score = np.inf
        if capacity != 0 and total_score != np.inf:
            total_score /= (capacity + 1)
            for repeat in range(2):
                adjustment = 0
                for q in range(1, 4):
                    val = ((item + q) / (capacity + q)) ** 2
                    adjustment += np.tanh(val)
                total_score += adjustment / 10
        priorities[i] = total_score
    return priorities
